(19,	NULL,	'Quibe de forno',	'quibe-de-forno',	'O Quibe de Forno é um prato típico da culinária árabe, feito com carne moída, trigo, cebola, alho, temperos e especiarias. É um prato muito saboroso e nutritivo, que pode ser servido como aperitivo ou como prato principal. O Quibe de Forno é preparad',	'http://gourmetsaudavel.com.br/wp-content/uploads/2020/01/prato-quibe-forno-500.jpg',	33.01,	8,	1,	'{\"carbs\": {\"dv\": \"7\", \"value\": \"21\"}, \"fiber\": {\"dv\": \"11\", \"value\": \"2,8\"}, \"energy\": {\"dv\": \"10\", \"value\": \"200Kcal=837kJ\"}, \"sodium\": {\"dv\": \"3\", \"value\": \"74\"}, \"protein\": {\"dv\": \"22\", \"value\": \"17\"}, \"fat_total\": {\"dv\": \"9\", \"value\": \"4,8\"}, \"fat_trans\": {\"dv\": \"**\", \"value\": \"0\"}, \"fat_saturated\": {\"dv\": \"10\", \"value\": \"2,2\"}}',	'2025-11-26 01:25:49',	'2025-11-25 22:26:24'),
