(26,	NULL,	'Bobó de Frango',	'bob-de-frango',	'Bobó de Frango é um prato típico brasileiro feito com frango em cubos, cebola, alho, tomate, azeite, mandioca batida, coentro, sal e pimenta. O frango é cozido e refogado com cebola, alho e tomate. Em seguida, é adicionado o lmandioca,os legumes o sa',	'http://gourmetsaudavel.com.br/wp-content/uploads/2020/01/prato-bobo-frango.png',	20.89,	7,	1,	'{\"carbs\": {\"dv\": \"2\", \"value\": \"7,3\"}, \"fiber\": {\"dv\": \"4\", \"value\": \"0,9\"}, \"energy\": {\"dv\": \"6\", \"value\": \"129Kcal=540kJ\"}, \"sodium\": {\"dv\": \"2\", \"value\": \"53\"}, \"protein\": {\"dv\": \"24\", \"value\": \"18\"}, \"fat_total\": {\"dv\": \"6\", \"value\": \"3,2\"}, \"fat_trans\": {\"dv\": \"**\", \"value\": \"0\"}, \"fat_saturated\": {\"dv\": \"3\", \"value\": \"0,7\"}}',	'2025-11-26 01:25:49',	'2025-11-25 22:26:24'),
