(29,	NULL,	'Bisteca ao Molho de Mostarda',	'bisteca-ao-molho-de-mostarda',	'A Bisteca ao Molho de Mostarda é um prato delicioso e saudável, feito com bistecas de porco frescas e marinadas em um molho de mostarda. O molho é feito com mostarda Dijon, leite desntado azeite, alho, tomilho, sal e pimenta. As bistecas são temperad',	NULL,	31.96,	5,	1,	'{\"carbs\": {\"dv\": \"1\", \"value\": \"2,8\"}, \"fiber\": {\"dv\": \"0\", \"value\": \"0\"}, \"energy\": {\"dv\": \"15\", \"value\": \"307Kcal=1285kJ\"}, \"sodium\": {\"dv\": \"5\", \"value\": \"118\"}, \"protein\": {\"dv\": \"30\", \"value\": \"22\"}, \"fat_total\": {\"dv\": \"42\", \"value\": \"23\"}, \"fat_trans\": {\"dv\": \"**\", \"value\": \"0\"}, \"fat_saturated\": {\"dv\": \"37\", \"value\": \"8,2\"}}',	'2025-11-26 01:25:49',	'2025-11-25 22:26:24'),
